def construct():
    """
    Asymmetric multi-layer structure with adaptive local search.
    Strategy: build a non-uniform k-layer digraph with complete bipartite edges
    between layers, then apply aggressive neutral-move local search to break
    the satisfaction plateau by coordinated 2-3 flip sequences.
    """
    np.random.seed(42)
    rng = np.random.default_rng(42)
    N = 49

    # Build initial non-uniform k-layer structure
    # Use k=4 layers with deliberately unequal sizes to break symmetry
    k = 4
    sizes = [13, 12, 12, 12]  # Unequal to avoid algebraic balance
    assert sum(sizes) == N

    starts = [0]
    for s in sizes:
        starts.append(starts[-1] + s)

    A = np.zeros((N, N), dtype=np.int8)

    # Complete bipartite edges between consecutive layers (cyclically)
    for c in range(k):
        nc = (c + 1) % k
        for u in range(starts[c], starts[c + 1]):
            for v in range(starts[nc], starts[nc + 1]):
                A[u, v] = 1

    # Add self-loop within each layer (except first vertex) to boost out-degree
    for c in range(k):
        for w in range(starts[c] + 1, starts[c + 1]):
            A[w, starts[c]] = 1

    # Aggressive neutral-move local search with 2-3 flip coordination
    best_score_val = score(A)[0]
    plateau_steps = 0
    max_plateau = 200
    iteration_count = 0
    max_iterations = 4000

    while iteration_count < max_iterations:
        improved = False

        # Try single arc flips that are neutral or better
        for attempt in range(min(500, max_iterations - iteration_count)):
            i, j = rng.integers(N, size=2)
            if i == j:
                continue

            iteration_count += 1
            old = int(A[i, j])

            if old:
                A[i, j] = 0
            else:
                if A[j, i]:  # Avoid 2-cycles
                    continue
                A[i, j] = 1

            s = score(A)
            if s is not None:
                new_score = s[0]
                if new_score <= best_score_val:
                    best_score_val = new_score
                    plateau_steps = 0
                    if new_score < best_score_val - 1e-9:
                        improved = True
                        break
                else:
                    A[i, j] = old
            else:
                A[i, j] = old

        # Try coordinated 2-flip sequences on the neutral plateau
        if not improved:
            for attempt in range(min(300, max_iterations - iteration_count)):
                i1, j1 = rng.integers(N, size=2)
                if i1 == j1:
                    continue
                i2, j2 = rng.integers(N, size=2)
                if i2 == j2:
                    continue

                iteration_count += 1
                old1, old2 = int(A[i1, j1]), int(A[i2, j2])

                # Flip both
                if old1:
                    A[i1, j1] = 0
                else:
                    if A[j1, i1]:
                        A[i1, j1] = old1
                        continue
                    A[i1, j1] = 1

                if old2:
                    A[i2, j2] = 0
                else:
                    if A[j2, i2]:
                        A[i2, j2] = old2
                        A[i1, j1] = old1
                        continue
                    A[i2, j2] = 1

                s = score(A)
                if s is not None:
                    new_score = s[0]
                    if new_score <= best_score_val:
                        best_score_val = new_score
                        plateau_steps = 0
                        if new_score < best_score_val - 1e-9:
                            improved = True
                    else:
                        A[i1, j1] = old1
                        A[i2, j2] = old2
                else:
                    A[i1, j1] = old1
                    A[i2, j2] = old2

        # Try coordinated 3-flip sequences
        if not improved and iteration_count < max_iterations - 100:
            for attempt in range(min(200, max_iterations - iteration_count)):
                flips = [(rng.integers(N), rng.integers(N)) for _ in range(3)]
                if any(i == j for i, j in flips):
                    continue

                iteration_count += 1
                olds = [int(A[i, j]) for i, j in flips]

                valid = True
                for i, j in flips:
                    if A[i, j] == 0 and A[j, i] == 1:
                        valid = False
                        break

                if not valid:
                    continue

                for i, j in flips:
                    A[i, j] = 1 - A[i, j]

                s = score(A)
                if s is not None:
                    new_score = s[0]
                    if new_score <= best_score_val:
                        best_score_val = new_score
                        plateau_steps = 0
                    else:
                        for (i, j), old in zip(flips, olds):
                            A[i, j] = old
                else:
                    for (i, j), old in zip(flips, olds):
                        A[i, j] = old

        plateau_steps += 1
        if plateau_steps >= max_plateau or iteration_count >= max_iterations:
            break

    return A
